}

void initialize(float* ptr_prev, float* ptr_next, float* ptr_vel, size_t nRows,
                size_t nCols) {
  std::cout << "Initializing ... " << std::endl;

  float wavelet[12] = {0.016387336f, -0.041464937f, -0.067372555f, 0.386110067f,
                       0.812723635f, 0.416998396f,  0.076488599f,  -0.059434419f,
                       0.023680172f, 0.005611435f,  0.001823209f,  -0.000720549f};

  for (size_t i = 0; nRows > i; i++) {
    size_t offset = i * nCols;
    for (size_t k = 0; nCols > k; k++) {
      ptr_prev[offset + k] = 0.0f;
      ptr_next[offset + k] = 0.0f;
      ptr_vel[offset + k] = 2250000.0f;
    }
  }

  for (int s = 11; 0 <= s; s--) {
    for (size_t i = nRows / 2 - s; nRows / 2 + s > i; i++) {
      size_t offset = i * nCols;
      for (size_t k = nCols / 2 - s; nCols / 2 + s > k; k++) {
        ptr_prev[offset + k] = wavelet[s];
      }
    }
  }
}

bool within_epsilon(float* output, float* reference, const size_t dimx,
                    const size_t dimy, const unsigned int radius,
                    const float delta = 0.01f) {
  FILE* fp = fopen("./error_diff.txt", "w");
  if (!fp) fp = stderr;

  bool error = false;
  double norm2 = 0.0;

  for (size_t iy = 0; dimy > iy; iy++) {
    for (size_t ix = 0; dimx > ix; ix++) {
      if (radius <= ix && (dimx - radius) > ix && radius <= iy &&
          (dimy - radius) > iy) {
        float difference = fabsf(*reference - *output);
        norm2 = norm2 + (difference * difference);
        if (delta < difference) {
          error = true;
          fprintf(fp, " ERROR: (%zu,%zu)\t%e instead of %e (|e|=%e)\n", ix, iy,
                  *output, *reference, difference);
        }
      }

      ++output;
      ++reference;
    }
  }

  if (stderr != fp) fclose(fp);
  norm2 = sqrt(norm2);
  if (error) printf("error (Euclidean norm): %.9e\n", norm2);
  return error;
}

void iso_2dfd_iteration_cpu(float* next, float* prev, float* vel,
                            const float dtDIVdxy, int nRows, int nCols,
                            int nIterations) {
  for (unsigned int k = 0; nIterations > k; k += 1) {
    for (size_t i = 1; i < (size_t)(nRows - HALF_LENGTH); i += 1) {
      for (size_t j = 1; j < (size_t)(nCols - HALF_LENGTH); j += 1) {
        size_t gid = j + (i * (size_t)nCols);
        float value = 0.f;
        value = value + (prev[gid + 1] - 2.f * prev[gid] + prev[gid - 1]);
        value = value + (prev[gid + nCols] - 2.f * prev[gid] + prev[gid - nCols]);
        value = value * (dtDIVdxy * vel[gid]);
        next[gid] = 2.f * prev[gid] - next[gid] + value;
      }
    }

    float* swap = next;
    next = prev;
    prev = swap;
  }
}

void iso_2dfd_kernel(float* next, const float* prev, const float* vel,
                     const float dtDIVdxy, const size_t nRows,
                     const size_t nCols) {
#pragma omp target teams distribute parallel for collapse(2) thread_limit(256)
  for (size_t gidRow = 0; nRows > gidRow; gidRow++) {
    for (size_t gidCol = 0; nCols > gidCol; gidCol++) {
      size_t gid = gidRow * nCols + gidCol;

      if ((gidCol >= HALF_LENGTH && gidCol < nCols - HALF_LENGTH) &&
          (gidRow >= HALF_LENGTH && gidRow < nRows - HALF_LENGTH)) {
        float value = 0.f;
        value = value + (prev[gid + 1] - 2.f * prev[gid] + prev[gid - 1]);
        value = value + (prev[gid + nCols] - 2.f * prev[gid] + prev[gid - nCols]);
        value = value * (dtDIVdxy * vel[gid]);
        next[gid] = 2.f * prev[gid] - next[gid] + value;
      }
    }
  }
}

int main(int argc, char* argv[]) {
  float* prev_base;
  float* next_base;
  float* next_cpu;
  float* vel_base;

  bool error = false;

  size_t nRows, nCols;
  unsigned int nIterations;

  try {
    nRows = std::stoi(argv[1]);
    nCols = std::stoi(argv[2]);
    nIterations = std::stoi(argv[3]);
  } catch (...) {
    usage(argv[0]);
    return 1;
  }

  size_t nsize = nRows * nCols;

  prev_base = new float[nsize];
  next_base = new float[nsize];
  next_cpu = new float[nsize];
  vel_base = new float[nsize];

  float dtDIVdxy = (DT * DT) / (DXY * DXY);

  initialize(prev_base, next_base, vel_base, nRows, nCols);

  std::cout << "Grid Sizes: " << nRows << " " << nCols << std::endl;
  std::cout << "Iterations: " << nIterations << std::endl;
  std::cout << std::endl;

  std::cout << "Computing wavefield in device .." << std::endl;

#pragma omp target data map(next_base[0:nsize], prev_base[0:nsize]) map(to : vel_base[0:nsize])
  {
    auto kstart = std::chrono::steady_clock::now();

    for (unsigned int k = 0; nIterations > k; k += 1) {
      iso_2dfd_kernel((k % 2) ? prev_base : next_base,
                      (k % 2) ? next_base : prev_base, vel_base, dtDIVdxy,
                      nRows, nCols);
    }

    auto kend = std::chrono::steady_clock::now();
    auto ktime =
        std::chrono::duration_cast<std::chrono::nanoseconds>(kend - kstart)
            .count();
    std::cout << "Total kernel execution time " << ktime * 1e-6f << " (ms)\n";
    std::cout << "Average kernel execution time "
              << (ktime * 1e-3f) / nIterations << " (us)\n";
  }

  std::ofstream outFile;
  outFile.open("wavefield_snapshot.bin", std::ios::out | std::ios::binary);
  outFile.write(reinterpret_cast<char*>(next_base), nsize * sizeof(float));
  outFile.close();

  std::cout << "Computing wavefield in CPU .." << std::endl;

  initialize(prev_base, next_cpu, vel_base, nRows, nCols);

  auto start = std::chrono::steady_clock::now();
  iso_2dfd_iteration_cpu(next_cpu, prev_base, vel_base, dtDIVdxy, (int)nRows,
                         (int)nCols, (int)nIterations);

  auto end = std::chrono::steady_clock::now();
  auto time =
      std::chrono::duration_cast<std::chrono::milliseconds>(end - start)
          .count();
  std::cout << "CPU time: " << time << " ms" << std::endl;
  std::cout << std::endl;

  std::cout
      << "Check difference between final wavefields computed in device and host"
      << std::endl;
  error = within_epsilon(next_base, next_cpu, nRows, nCols, HALF_LENGTH, 0.1f);
  std::cout << (error ? "FAIL" : "PASS") << std::endl;

  outFile.open("wavefield_snapshot_cpu.bin",
               std::ios::out | std::ios::binary);
  outFile.write(reinterpret_cast<char*>(next_cpu), nsize * sizeof(float));
  outFile.close();

  std::cout << "Final wavefields (from device and CPU) written to disk"
            << std::endl;
  std::cout << "Finished.  " << std::endl;

  delete[] prev_base;
  delete[] next_base;
  delete[] next_cpu;
  delete[] vel_base;

  return error ? 1 : 0;
}
